// Standalone router — NOT generated by Stacked.
//
// Keeps all route names and argument classes identical to what the Stacked
// generator produced in app.router.dart so that existing call sites
// (NavigationService.navigateTo, NavigationService.replaceWith, etc.) continue
// to work without any changes.
//
// When a view is fully migrated off Stacked ViewModels the route entry here
// can be updated independently without touching the generated file.

import 'package:flutter/material.dart';
import 'package:freecodecamp/app/app.router.dart'
    show
        Routes,
        EpisodeViewArguments,
        NewsTutorialViewArguments,
        NewsBookmarkTutorialViewArguments,
        NewsFeedViewArguments,
        NewsAuthorViewArguments,
        NewsImageViewArguments,
        ChallengeTemplateViewArguments,
        ChapterViewArguments,
        ChapterBlockViewArguments,
        NativeLoginViewArguments,
        SuperBlockViewArguments;
import 'package:freecodecamp/ui/views/code_radio/code_radio_view.dart';
import 'package:freecodecamp/ui/views/learn/challenge/templates/template_view.dart';
import 'package:freecodecamp/ui/views/learn/chapter/chapter_block_view.dart';
import 'package:freecodecamp/ui/views/learn/chapter/chapter_view.dart';
import 'package:freecodecamp/ui/views/learn/daily_challenge/daily_challenge_view.dart';
import 'package:freecodecamp/ui/views/learn/landing/landing_view.dart';
import 'package:freecodecamp/ui/views/learn/superblock/superblock_view.dart';
import 'package:freecodecamp/ui/views/login/native_login_view.dart';
import 'package:freecodecamp/ui/views/news/news-author/news_author_view.dart';
import 'package:freecodecamp/ui/views/news/news-bookmark/news_bookmark_view.dart';
import 'package:freecodecamp/ui/views/news/news-feed/news_feed_view.dart';
import 'package:freecodecamp/ui/views/news/news-image-viewer/news_image_view.dart';
import 'package:freecodecamp/ui/views/news/news-tutorial/news_tutorial_view.dart';
import 'package:freecodecamp/ui/views/news/news-view-handler/news_view_handler_view.dart';
import 'package:freecodecamp/ui/views/podcast/episode/episode_view.dart';
import 'package:freecodecamp/ui/views/podcast/podcast-list/podcast_list_view.dart';
import 'package:freecodecamp/ui/views/profile/profile_view.dart';
import 'package:freecodecamp/ui/views/settings/delete-account/delete_account_view.dart';
import 'package:freecodecamp/ui/views/settings/settings_view.dart';

/// Returns a [Route] for the given [RouteSettings], or `null` if the route is
/// unknown.  Plug this directly into [MaterialApp.onGenerateRoute].
Route<dynamic>? generateRoute(RouteSettings settings) {
  switch (settings.name) {
    // ------------------------------------------------------------------
    // Routes without arguments
    // ------------------------------------------------------------------
    case Routes.learnLandingView:
      return MaterialPageRoute<dynamic>(
        builder: (_) => const LearnLandingView(),
        settings: settings,
      );

    case Routes.newsViewHandlerView:
      return MaterialPageRoute<dynamic>(
        builder: (_) => const NewsViewHandlerView(),
        settings: settings,
      );

    case Routes.podcastListView:
      return MaterialPageRoute<dynamic>(
        builder: (_) => const PodcastListView(),
        settings: settings,
      );

    case Routes.codeRadioView:
      return MaterialPageRoute<dynamic>(
        builder: (_) => const CodeRadioView(),
        settings: settings,
      );

    case Routes.profileView:
      return MaterialPageRoute<dynamic>(
        builder: (_) => const ProfileView(),
        settings: settings,
      );

    case Routes.settingsView:
      return MaterialPageRoute<dynamic>(
        builder: (_) => const SettingsView(),
        settings: settings,
      );

    case Routes.deleteAccountView:
      return MaterialPageRoute<dynamic>(
        builder: (_) => const DeleteAccountView(),
        settings: settings,
      );

    case Routes.dailyChallengeView:
      return MaterialPageRoute<dynamic>(
        builder: (_) => const DailyChallengeView(),
        settings: settings,
      );

    // ------------------------------------------------------------------
    // Routes with arguments
    // ------------------------------------------------------------------
    case Routes.episodeView:
      final args = settings.arguments as EpisodeViewArguments;
      return MaterialPageRoute<dynamic>(
        builder: (_) => EpisodeView(
          key: args.key,
          episode: args.episode,
          podcast: args.podcast,
        ),
        settings: settings,
      );

    case Routes.newsTutorialView:
      final args = settings.arguments as NewsTutorialViewArguments;
      return MaterialPageRoute<dynamic>(
        builder: (_) => NewsTutorialView(
          key: args.key,
          refId: args.refId,
          slug: args.slug,
        ),
        settings: settings,
      );

    case Routes.newsBookmarkTutorialView:
      final args = settings.arguments as NewsBookmarkTutorialViewArguments;
      return MaterialPageRoute<dynamic>(
        builder: (_) => NewsBookmarkTutorialView(
          key: args.key,
          tutorial: args.tutorial,
        ),
        settings: settings,
      );

    case Routes.newsFeedView:
      final args = settings.arguments is NewsFeedViewArguments
          ? settings.arguments as NewsFeedViewArguments
          : const NewsFeedViewArguments();
      return MaterialPageRoute<dynamic>(
        builder: (_) => NewsFeedView(
          key: args.key,
          tagSlug: args.tagSlug,
          authorId: args.authorId,
          fromAuthor: args.fromAuthor,
          fromTag: args.fromTag,
          fromSearch: args.fromSearch,
          tutorials: args.tutorials,
          subject: args.subject,
        ),
        settings: settings,
      );

    case Routes.newsAuthorView:
      final args = settings.arguments as NewsAuthorViewArguments;
      return MaterialPageRoute<dynamic>(
        builder: (_) => NewsAuthorView(
          key: args.key,
          authorSlug: args.authorSlug,
        ),
        settings: settings,
      );

    case Routes.newsImageView:
      final args = settings.arguments as NewsImageViewArguments;
      return MaterialPageRoute<dynamic>(
        builder: (_) => NewsImageView(
          key: args.key,
          imgUrl: args.imgUrl,
          isDataUrl: args.isDataUrl,
        ),
        settings: settings,
      );

    case Routes.challengeTemplateView:
      final args = settings.arguments as ChallengeTemplateViewArguments;
      return MaterialPageRoute<dynamic>(
        builder: (_) => ChallengeTemplateView(
          key: args.key,
          block: args.block,
          challengeId: args.challengeId,
          challengeDate: args.challengeDate,
        ),
        settings: settings,
      );

    case Routes.chapterView:
      final args = settings.arguments as ChapterViewArguments;
      return MaterialPageRoute<dynamic>(
        builder: (_) => ChapterView(
          key: args.key,
          superBlockDashedName: args.superBlockDashedName,
          superBlockName: args.superBlockName,
        ),
        settings: settings,
      );

    case Routes.chapterBlockView:
      final args = settings.arguments as ChapterBlockViewArguments;
      return MaterialPageRoute<dynamic>(
        builder: (_) => ChapterBlockView(
          key: args.key,
          moduleName: args.moduleName,
          blocks: args.blocks,
        ),
        settings: settings,
      );

    case Routes.nativeLoginView:
      final args = settings.arguments is NativeLoginViewArguments
          ? settings.arguments as NativeLoginViewArguments
          : const NativeLoginViewArguments();
      return MaterialPageRoute<dynamic>(
        builder: (_) => NativeLoginView(
          key: args.key,
          fromButton: args.fromButton,
        ),
        settings: settings,
      );

    case Routes.superBlockView:
      final args = settings.arguments as SuperBlockViewArguments;
      return MaterialPageRoute<dynamic>(
        builder: (_) => SuperBlockView(
          key: args.key,
          superBlockDashedName: args.superBlockDashedName,
          superBlockName: args.superBlockName,
          hasInternet: args.hasInternet,
        ),
        settings: settings,
      );

    default:
      return null;
  }
}
